<template>
  <div class="submit-form">
    <div v-if="!submitted">
      <div class="form-group">
        <h4>Добавить продукт</h4>
        <label for="title">Название</label>
        <input
          type="text"
          class="form-control"
          id="title"
          required
          v-model="tutorial.title"
          name="title"
        />
      </div>

      <div class="form-group">
        <label for="description">Срок годности</label>
        <input
          class="form-control"
          id="description"
          type="date"
          v-model="tutorial.description"
          name="description"
        />
      </div>
      <div class="form-group">
        <label for="proteins">Белки</label>
        <input
          type="text"
          class="form-control"
          id="proteins"
          v-model="tutorial.proteins"
        />
        <label for="fats">Жиры</label>
        <input
          type="text"
          class="form-control"
          id="fats"
          v-model="tutorial.fats"
        />
        <label for="carbohydrates">Углеводы</label>
        <input
          type="text"
          class="form-control"
          id="carbohydrates"
          v-model="tutorial.carbohydrates"
        />
      </div>

      <button @click="saveTutorial" class="btn btn-success">Добавить</button>
    </div>

    <div v-else>
      <h4>Успешно добавлено!</h4>
      <button class="btn btn-success" @click="newTutorial">Добавить еще</button>
    </div>
  </div>
</template>

<script>
import TutorialDataService from "../services/TutorialDataService";

export default {
  name: "add-tutorial",
  data() {
    return {
      tutorial: {
        title: "",
        description: "",
        published: false,
        proteins: 0,
        fats: 0,
        carbohydrates: 0,
      },
      submitted: false,
    };
  },
  methods: {
    saveTutorial() {
      var data = {
        title: this.tutorial.title,
        description: this.tutorial.description,
        published: false,
        proteins: this.tutorial.proteins,
        fats: this.tutorial.fats,
        carbohydrates: this.tutorial.carbohydrates,
      };

      TutorialDataService.create(data)
        .then(() => {
          console.log("Created new item successfully!");
          this.submitted = true;
        })
        .catch((e) => {
          console.log(e);
        });
    },

    newTutorial() {
      this.submitted = false;
      this.tutorial = {
        title: "",
        description: "",
        published: false,
        proteins: 0,
        fats: 0,
        carbohydrates: 0,
      };
    },
  },
};
</script>

<style>
.submit-form {
  max-width: 300px;
  margin: auto;
}
</style>
