<template>
  <section class="product-list">
    <div class="product-list__container">
      <h1>Список продуктов</h1>
      <TutorialAdd />

      <div class="summPFC">
        <h4>Общее количество БЖУ</h4>
        <ul>
          <li><span>Белки:</span> {{ calcProteins() }}</li>
          <li><span>Жиры:</span> {{ calcFats() }}</li>
          <li><span>Углеводы:</span> {{ calcCarbohydrates() }}</li>
        </ul>
      </div>
      <ul class="list-group">
        <h4 v-if="tutorials.length">Список продуктов</h4>
        <h4 v-else>Список продуктов пуст</h4>
        <li
          class="list-group-item"
          :class="{ active: index == currentIndex }"
          v-for="(tutorial, index) in tutorials"
          :key="index"
          @click="setActiveTutorial(tutorial, index)"
        >
          {{ tutorial.title }} <br />
          <span class="date" v-if="tutorial.description"
          > {{ tutorial.description }}</span>
        </li>
      </ul>
      <div class="modal">
        <div v-if="currentTutorial">
          <tutorial-details
            :tutorial="currentTutorial"
            @refreshList="refreshList"
          />
        </div>
        <div class="toEdit" v-else>
          <p>Для редактирования, нажмите на продукт</p>
        </div>
      </div>
      <button class="btn-danger" @click="removeAllTutorials">
        Удалить все
      </button>
    </div>
  </section>
</template>

<script>
import TutorialDataService from "../services/TutorialDataService";
import TutorialDetails from "./Tutorial";
import TutorialAdd from "./AddTutorial";
import "@/assets/productList.scss";
export default {
  name: "tutorials-list",
  components: { TutorialDetails, TutorialAdd },
  data() {
    return {
      tutorials: [],
      currentTutorial: null,
      currentIndex: -1,
    };
  },
  methods: {
    onDataChange(items) {
      let _tutorials = [];

      items.forEach((item) => {
        let key = item.key;
        let data = item.val();
        _tutorials.push({
          key: key,
          title: data.title,
          description: data.description,
          published: data.published,
          proteins: data.proteins,
          fats: data.fats,
          carbohydrates: data.carbohydrates,
        });
      });

      this.tutorials = _tutorials;
    },

    refreshList() {
      this.currentTutorial = null;
      this.currentIndex = -1;
    },

    setActiveTutorial(tutorial, index) {
      this.currentTutorial = tutorial;
      this.currentIndex = index;
    },

    removeAllTutorials() {
      TutorialDataService.deleteAll()
        .then(() => {
          this.refreshList();
        })
        .catch((e) => {
          console.log(e);
        });
    },

    calcProteins() {
      let pr = 0;
      for (let item of this.tutorials) {
        pr += Number(item.proteins);
      }
      return Number(pr);
    },
    calcFats() {
      let pr = 0;
      for (let item of this.tutorials) {
        pr += Number(item.fats);
      }
      return Number(pr);
    },
    calcCarbohydrates() {
      let pr = 0;
      for (let item of this.tutorials) {
        pr += Number(item.carbohydrates);
      }
      return Number(pr);
    },
    currentDate(){
      let date = new Date();
      return date = date.toLocaleDateString()
    }
  },
  mounted() {
    TutorialDataService.getAll().on("value", this.onDataChange);
  },
  beforeUnmount() {
    TutorialDataService.getAll().off("value", this.onDataChange);
  },
};
</script>

<style>
.list {
  text-align: left;
  max-width: 750px;
  margin: auto;
}
</style>
