<template>
  <div v-if="currentTutorial" class="edit-form">
    <h4>Продукт</h4>
    <form>
      <div class="form-group">
        <label for="title">Название</label>
        <input
          type="text"
          class="form-control"
          id="title"
          v-model="currentTutorial.title"
        />
      </div>

      <div class="form-group">
        <label for="description">Срок годности</label>
        <input
          type="date"
          class="form-control"
          id="description"
          v-model="currentTutorial.description"
        />
      </div>
      <div class="form-group">
        <label for="proteins">Белки</label>
        <input
          type="text"
          class="form-control"
          id="proteins"
          v-model="currentTutorial.proteins"
        />
        <label for="fats">Жиры</label>
        <input
          type="text"
          class="form-control"
          id="fats"
          v-model="currentTutorial.fats"
        />
        <label for="carbohydrates">Углеводы</label>
        <input
          type="text"
          class="form-control"
          id="carbohydrates"
          v-model="currentTutorial.carbohydrates"
        />
      </div>

      <div class="form-group">
        <label><strong>Статус:</strong></label>
        {{ currentTutorial.published ? "Опубликован" : "Ожидание" }}
      </div>
    </form>
    <div class="btn-row">
      <button
        class="badge badge-primary mr-2"
        v-if="currentTutorial.published"
        @click="updatePublished(false)"
      >
        Неопубликован
      </button>
      <button
        v-else
        class="badge badge-primary mr-2"
        @click="updatePublished(true)"
      >
        Опубликован
      </button>
      <button type="submit" class="badge badge-success" @click="updateTutorial">
        Обновить
      </button>
      <button class="badge badge-danger mr-2" @click="deleteTutorial">
        Удалить
      </button>
    </div>

    <p>{{ message }}</p>
  </div>

  <div v-else>
    <br />
    <p>Please click on a Tutorial...</p>
  </div>
</template>

<script>
import TutorialDataService from "../services/TutorialDataService";

export default {
  name: "tutorial-item",
  props: ["tutorial"],
  data() {
    return {
      currentTutorial: null,
      message: "",
    };
  },
  watch: {
    tutorial: function (tutorial) {
      this.currentTutorial = { ...tutorial };
      this.message = "";
    },
  },
  methods: {
    updatePublished(status) {
      TutorialDataService.update(this.currentTutorial.key, {
        published: status,
      })
        .then(() => {
          this.currentTutorial.published = status;
          this.message = "The status was updated successfully!";
        })
        .catch((e) => {
          console.log(e);
        });
    },

    updateTutorial() {
      const data = {
        title: this.currentTutorial.title,
        description: this.currentTutorial.description,
        proteins: this.currentTutorial.proteins,
        fats: this.currentTutorial.fats,
        carbohydrates: this.currentTutorial.carbohydrates,
      };

      TutorialDataService.update(this.currentTutorial.key, data)
        .then(() => {
          this.message = "The tutorial was updated successfully!";
        })
        .catch((e) => {
          console.log(e);
        });
    },

    deleteTutorial() {
      TutorialDataService.delete(this.currentTutorial.key)
        .then(() => {
          this.$emit("refreshList");
        })
        .catch((e) => {
          console.log(e);
        });
    },
  },
  mounted() {
    this.message = "";
    this.currentTutorial = { ...this.tutorial };
  },
};
</script>

<style>
.edit-form {
  margin: auto;
}
</style>
